import {
  ChangeDetectionStrategy,
  Component,
  computed,
  contentChildren,
  effect,
  ElementRef,
  input,
  output,
  ViewEncapsulation,
} from '@angular/core';

import { NgIcon } from '@ng-icons/core';

import { HbMenuImports } from '{{alias}}/menu';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HbAvatarComponent } from './avatar.component';
import { avatarGroupChipVariants, avatarGroupVariants } from './avatar-group.variants';
import type { HbAvatarShape, HbAvatarSize } from './avatar.variants';

@Component({
  selector: 'hb-avatar-group',
  imports: [NgIcon, HbMenuImports],
  template: `
    <ng-content />

    @if (overflowCount() > 0) {
      <span
        class="inline-flex"
        [hbMenuTriggerFor]="overflowMenu"
        #overflowTrigger="hbMenuTrigger"
      >
        <div
          [class]="chipClasses()"
          [style.width.px]="customSize()"
          [style.height.px]="customSize()"
          role="button"
          tabindex="0"
          data-slot="avatar-group-overflow"
          (click)="hbOverflowClick.emit(); overflowTrigger.toggle()"
        >
          @if (hbOverflowIcon()) {
            <ng-icon [name]="hbOverflowIcon()" class="[&>svg]:size-[45%]" />
          } @else {
            +{{ overflowCount() }}
          }
        </div>
      </span>
    }

    <ng-template #overflowMenu>
      <hb-menu class="min-w-44">
        @for (avatar of hiddenAvatars(); track $index) {
          <button hb-menu-item type="button">{{ avatarLabel(avatar) }}</button>
        }
      </hb-menu>
    </ng-template>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'groupClasses()',
    role: 'group',
  },
  exportAs: 'hbAvatarGroup',
})
export class HbAvatarGroupComponent {
  readonly hbOrientation = input<'horizontal' | 'vertical'>('horizontal');
  readonly hbMax = input<number | null>(null);
  readonly hbOverflowIcon = input('');
  readonly hbSpacing = input<'sm' | 'md' | 'lg'>('md');
  readonly hbSize = input<HbAvatarSize | number>('md');
  readonly hbShape = input<HbAvatarShape>('circle');
  readonly class = input<ClassValue>('');

  readonly hbOverflowClick = output<void>();

  private readonly avatars = contentChildren(HbAvatarComponent, { read: ElementRef });
  private readonly avatarComponents = contentChildren(HbAvatarComponent);

  protected readonly hiddenAvatars = computed(() => {
    const max = this.hbMax();
    if (max == null || max <= 0) return [];
    return this.avatarComponents().slice(max);
  });
  protected avatarLabel(avatar: HbAvatarComponent): string {
    return avatar.hbAlt() || avatar.hbFallback() || '—';
  }

  protected readonly total = computed(() => this.avatars().length);

  protected readonly overflowCount = computed(() => {
    const max = this.hbMax();
    if (max == null || max <= 0) return 0;
    return Math.max(0, this.total() - max);
  });

  private readonly namedSize = computed<HbAvatarSize>(() => {
    const size = this.hbSize();
    return typeof size === 'number' ? 'md' : size;
  });

  protected readonly customSize = computed(() => {
    const size = this.hbSize();
    return typeof size === 'number' ? size : null;
  });

  protected readonly groupClasses = computed(() =>
    cn(
      avatarGroupVariants({ orientation: this.hbOrientation(), spacing: this.hbSpacing() }),
      this.class(),
    ),
  );

  protected readonly chipClasses = computed(() =>
    avatarGroupChipVariants({ size: this.namedSize(), shape: this.hbShape() }),
  );

  constructor() {
    effect(() => {
      const max = this.hbMax();
      this.avatars().forEach((ref, index) => {
        const el = ref.nativeElement as HTMLElement;
        el.style.display = max != null && max > 0 && index >= max ? 'none' : '';
      });
    });
  }
}

import { cva } from 'class-variance-authority';

export const avatarGroupVariants = cva(
  'flex items-center [&>*]:ring-2 [&>*]:ring-background',
  {
    variants: {
      orientation: { horizontal: 'flex-row', vertical: 'flex-col' },
      spacing: { sm: '', md: '', lg: '' },
    },
    compoundVariants: [
      { orientation: 'horizontal', spacing: 'sm', class: '[&>*:not(:first-child)]:-ml-2' },
      { orientation: 'horizontal', spacing: 'md', class: '[&>*:not(:first-child)]:-ml-3' },
      { orientation: 'horizontal', spacing: 'lg', class: '[&>*:not(:first-child)]:-ml-4' },
      { orientation: 'vertical', spacing: 'sm', class: '[&>*:not(:first-child)]:-mt-2' },
      { orientation: 'vertical', spacing: 'md', class: '[&>*:not(:first-child)]:-mt-3' },
      { orientation: 'vertical', spacing: 'lg', class: '[&>*:not(:first-child)]:-mt-4' },
    ],
    defaultVariants: { orientation: 'horizontal', spacing: 'md' },
  },
);

export const avatarGroupChipVariants = cva(
  'relative inline-flex shrink-0 cursor-pointer items-center justify-center bg-muted font-medium text-muted-foreground',
  {
    variants: {
      size: {
        xs: 'size-6 text-[0.625rem]',
        sm: 'size-8 text-xs',
        md: 'size-10 text-sm',
        lg: 'size-14 text-lg',
        xl: 'size-20 text-2xl',
      },
      shape: { circle: 'rounded-full', square: 'rounded-md' },
    },
    defaultVariants: { size: 'md', shape: 'circle' },
  },
);

import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  contentChild,
  Directive,
  effect,
  input,
  output,
  signal,
  ViewEncapsulation,
} from '@angular/core';

import { NgIcon } from '@ng-icons/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import {
  avatarBadgeVariants,
  avatarFallbackVariants,
  avatarImageVariants,
  avatarStatusColors,
  avatarVariants,
  type HbAvatarBadgePosition,
  type HbAvatarShape,
  type HbAvatarSize,
  type HbAvatarStatus,
} from './avatar.variants';

@Directive({ selector: '[hbAvatarBadge]' })
export class HbAvatarBadgeDirective {}

@Component({
  selector: 'hb-avatar, [hb-avatar]',
  imports: [NgIcon],
  template: `
    @if (hbSrc() && !imageError()) {
      <img
        [src]="hbSrc()"
        [alt]="hbAlt()"
        [attr.loading]="hbPriority() ? 'eager' : 'lazy'"
        [attr.fetchpriority]="hbPriority() ? 'high' : null"
        [class]="imageClasses()"
        (error)="onImageError()"
        (load)="onImageLoad()"
      />
    } @else {
      <span [class]="fallbackClasses()">{{ hbFallback() }}</span>
    }

    @if (showBadge()) {
      <span [class]="badgeClasses()" [attr.aria-label]="hbStatus() ?? null" data-slot="avatar-badge">
        @if (hasCustomBadge()) {
          <ng-content select="[hbAvatarBadge]" />
        } @else if (hbBadgeIcon()) {
          <ng-icon [name]="hbBadgeIcon()" class="text-foreground [&>svg]:size-[70%]" />
        } @else {
          <span class="size-full rounded-full" [class]="statusColorClass()"></span>
        }
      </span>
    }
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'containerClasses()',
    '[style.width.px]': 'customSize()',
    '[style.height.px]': 'customSize()',
    role: 'img',
    '[attr.aria-label]': 'hbAlt() || hbFallback() || null',
    '[attr.data-status]': 'hbStatus() ?? null',
    '[attr.data-disabled]': 'hbDisabled() ? "" : null',
    '(click)': 'onClick()',
  },
  exportAs: 'hbAvatar',
})
export class HbAvatarComponent {
  readonly hbSrc = input('');
  readonly hbAlt = input('');
  readonly hbFallback = input('');
  readonly hbPriority = input(false, { transform: booleanAttribute });
  readonly hbSize = input<HbAvatarSize | number>('md');
  readonly hbShape = input<HbAvatarShape>('circle');
  readonly hbStatus = input<HbAvatarStatus | undefined>(undefined);
  readonly hbBadgePosition = input<HbAvatarBadgePosition>('bottom-right');
  readonly hbBadgeIcon = input('');
  readonly hbDisabled = input(false, { transform: booleanAttribute });
  readonly class = input<ClassValue>('');

  readonly hbClick = output<void>();

  protected readonly imageError = signal(false);
  protected readonly imageLoaded = signal(false);

  private readonly customBadgeSlot = contentChild(HbAvatarBadgeDirective);
  protected readonly hasCustomBadge = computed(() => this.customBadgeSlot() != null);

  constructor() {
    effect(() => {
      this.hbSrc();
      this.imageError.set(false);
      this.imageLoaded.set(false);
    });
  }

  private readonly namedSize = computed<HbAvatarSize>(() => {
    const size = this.hbSize();
    return typeof size === 'number' ? 'md' : size;
  });

  protected readonly customSize = computed(() => {
    const size = this.hbSize();
    return typeof size === 'number' ? size : null;
  });

  protected readonly containerClasses = computed(() =>
    cn(
      avatarVariants({ size: this.namedSize(), shape: this.hbShape() }),
      this.hbDisabled() ? 'pointer-events-none opacity-50' : '',
      this.class(),
    ),
  );
  protected readonly imageClasses = computed(() => avatarImageVariants({ shape: this.hbShape() }));
  protected readonly fallbackClasses = computed(() => avatarFallbackVariants({ shape: this.hbShape() }));
  protected readonly badgeClasses = computed(() =>
    avatarBadgeVariants({ position: this.hbBadgePosition(), size: this.namedSize() }),
  );

  protected readonly statusColorClass = computed(() => {
    const status = this.hbStatus();
    return status ? avatarStatusColors[status] : '';
  });

  protected readonly showBadge = computed(
    () => this.hasCustomBadge() || !!this.hbBadgeIcon() || !!this.hbStatus(),
  );

  protected onImageLoad(): void {
    this.imageLoaded.set(true);
    this.imageError.set(false);
  }

  protected onImageError(): void {
    this.imageError.set(true);
    this.imageLoaded.set(false);
  }

  protected onClick(): void {
    this.hbClick.emit();
  }
}

import { HbAvatarBadgeDirective, HbAvatarComponent } from './avatar.component';
import { HbAvatarGroupComponent } from './avatar-group.component';

export const HbAvatarImports = [
  HbAvatarComponent,
  HbAvatarBadgeDirective,
  HbAvatarGroupComponent,
] as const;

import { cva, type VariantProps } from 'class-variance-authority';

export const avatarVariants = cva('relative inline-flex shrink-0 select-none', {
  variants: {
    size: {
      xs: 'size-6 text-[0.625rem]',
      sm: 'size-8 text-xs',
      md: 'size-10 text-sm',
      lg: 'size-14 text-lg',
      xl: 'size-20 text-2xl',
    },
    shape: {
      circle: 'rounded-full',
      square: 'rounded-md',
    },
  },
  defaultVariants: { size: 'md', shape: 'circle' },
});

export const avatarImageVariants = cva('size-full object-cover', {
  variants: { shape: { circle: 'rounded-full', square: 'rounded-md' } },
  defaultVariants: { shape: 'circle' },
});

export const avatarFallbackVariants = cva(
  'flex size-full items-center justify-center bg-muted font-medium text-muted-foreground uppercase',
  {
    variants: { shape: { circle: 'rounded-full', square: 'rounded-md' } },
    defaultVariants: { shape: 'circle' },
  },
);

export const avatarBadgeVariants = cva(
  'absolute z-10 flex items-center justify-center rounded-full bg-background ring-2 ring-background',
  {
    variants: {
      position: {
        'top-right': 'top-[6%] right-[6%]',
        'top-left': 'top-[6%] left-[6%]',
        'bottom-right': 'right-[6%] bottom-[6%]',
        'bottom-left': 'bottom-[6%] left-[6%]',
      },
      size: {
        xs: 'size-2',
        sm: 'size-2.5',
        md: 'size-3',
        lg: 'size-3.5',
        xl: 'size-4',
      },
    },
    defaultVariants: { position: 'bottom-right', size: 'md' },
  },
);

export const avatarStatusColors: Record<HbAvatarStatus, string> = {
  online: 'bg-success',
  offline: 'bg-muted-foreground',
  away: 'bg-warning',
  busy: 'bg-destructive',
};

export type HbAvatarSize = NonNullable<VariantProps<typeof avatarVariants>['size']>;
export type HbAvatarShape = NonNullable<VariantProps<typeof avatarVariants>['shape']>;
export type HbAvatarStatus = 'online' | 'offline' | 'away' | 'busy';
export type HbAvatarBadgePosition = NonNullable<VariantProps<typeof avatarBadgeVariants>['position']>;

export * from './avatar.component';
export * from './avatar.variants';
export * from './avatar-group.component';
export * from './avatar-group.variants';
export * from './avatar.imports';

