import { ChangeDetectionStrategy, Component } from '@angular/core';

import { HbAvatarImports } from '@herbst/ui';

const portrait =
  'data:image/svg+xml,' +
  encodeURIComponent(
    "<svg xmlns='http://www.w3.org/2000/svg' width='80' height='80'>" +
      "<defs><linearGradient id='g' x1='0' y1='0' x2='1' y2='1'>" +
      "<stop offset='0' stop-color='#A64B2A'/><stop offset='1' stop-color='#6B7A55'/>" +
      '</linearGradient></defs>' +
      "<rect width='80' height='80' fill='url(#g)'/></svg>",
  );

@Component({
  selector: 'hb-demo-avatar-basic',
  imports: [HbAvatarImports],
  template: `
    <div class="flex items-center gap-4">
      <hb-avatar [hbSrc]="portrait" hbAlt="Kauan Herbst" hbFallback="KH" hbPriority hbSize="lg" />
      <hb-avatar hbFallback="NA" hbSize="lg" />
      <hb-avatar hbFallback="Q" hbShape="square" hbSize="lg" />
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoAvatarBasicComponent {
  protected readonly portrait = portrait;
}

import { ChangeDetectionStrategy, Component, signal } from '@angular/core';

import { HbAvatarImports } from '@herbst/ui';

@Component({
  selector: 'hb-demo-avatar-group',
  imports: [HbAvatarImports],
  template: `
    <div class="flex flex-col items-start gap-3">
      <hb-avatar-group [hbMax]="3" hbSpacing="md" hbSize="md" (hbOverflowClick)="expand()">
        <hb-avatar hbFallback="KH" />
        <hb-avatar hbFallback="NA" />
        <hb-avatar hbFallback="BS" />
        <hb-avatar hbFallback="LC" />
        <hb-avatar hbFallback="AM" />
      </hb-avatar-group>

      <p class="font-mono text-[12px] text-muted-foreground">Overflow clicks: {{ clicks() }}</p>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoAvatarGroupComponent {
  protected readonly clicks = signal(0);

  protected expand(): void {
    this.clicks.update((n) => n + 1);
  }
}

import { ChangeDetectionStrategy, Component, signal } from '@angular/core';

import { HbAvatarImports } from '@herbst/ui';

@Component({
  selector: 'hb-demo-avatar-interactive',
  imports: [HbAvatarImports],
  template: `
    <div class="flex items-center gap-4">
      <hb-avatar
        hbFallback="KH"
        hbSize="lg"
        class="cursor-pointer"
        (hbClick)="taps.set(taps() + 1)"
      />
      <hb-avatar hbFallback="NA" hbSize="lg" hbDisabled />

      <p class="font-mono text-[12px] text-muted-foreground">Tapped {{ taps() }}×</p>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoAvatarInteractiveComponent {
  protected readonly taps = signal(0);
}

import { ChangeDetectionStrategy, Component } from '@angular/core';

import { HbAvatarImports } from '@herbst/ui';

@Component({
  selector: 'hb-demo-avatar-sizes',
  imports: [HbAvatarImports],
  template: `
    <div class="flex flex-wrap items-center gap-4">
      <hb-avatar hbFallback="XS" hbSize="xs" />
      <hb-avatar hbFallback="SM" hbSize="sm" />
      <hb-avatar hbFallback="MD" hbSize="md" />
      <hb-avatar hbFallback="LG" hbSize="lg" />
      <hb-avatar hbFallback="XL" hbSize="xl" />
      <hb-avatar hbFallback="72" [hbSize]="72" />
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoAvatarSizesComponent {}
